import functools

def cache_api_response(func):
    _cache = {}

    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        # Create a hashable key from function arguments
        # kwargs need to be sorted to ensure consistent key generation
        key = (args, frozenset(sorted(kwargs.items())))

        if key in _cache:
            return _cache[key]
        else:
            result = func(*args, **kwargs)
            _cache[key] = result
            return result
    return wrapper
